using namespace std;
NP phigrOS
{
	il ll read()
	{
		ll x=0,f=1;char ch=gc();
		wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=gc();}
		wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
		return x*f;
	}
	void write(ll x)
	{
		if(x<0)pc('-'),x=-x;
		if(x>9)write(x/10);
		pc(x%10+'0');
	}
	void writeln(ll x)
	{
		write(x);
		puts("");
	}
}
using NP phigrOS;
CI MAXN=1e5+10;
int n,a[MAXN],p[MAXN][20],ans;
void f(int x)
{
	if(x==1)return;
	unordered_map<int,int>t;
	FOR(i,2,sqrt(x))
	{
		wh(x%i==0)
		{
			p[i][++t[i]]++;
			x/=i;
		}
		if(x==1)return;
	}
	p[x][++t[x]]++;
}
signed main()
{
	n=read();
	FOR(i,1,n)
	{
		a[i]=read();
		f(a[i]);
	}
	FOR(i,2,1e5)
	{
		FOR(j,1,19)
		{
			if(!p[i][j])break;
			ans+=min(p[i][j],n-p[i][j]);
		}
	}
	writeln(ans);
	return 0;
}
